import { Component, OnInit, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { Report } from '../../core/models';
import { AdminApiService } from '../../core/services/admin-api.service';
import { ToastService } from '../../core/services/toast.service';

// Placeholder so the template renders before /admin/reports resolves.
const EMPTY_REPORT: Report = {
  id: '',
  reportedName: '',
  reportedId: '',
  reporterName: '',
  reason: '',
  status: 'pending',
  createdAt: '',
  details: '',
};

@Component({
  selector: 'app-report-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './report-detail.component.html',
  styleUrl: './report-detail.component.css',
})
export class ReportDetailComponent implements OnInit {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private admin = inject(AdminApiService);
  private toast = inject(ToastService);

  readonly reportId = this.route.snapshot.paramMap.get('reportId') ?? '';

  readonly reports = signal<Report[]>([]);
  readonly resolution = signal<'ban' | 'dismiss' | null>(null);

  // There is no GET /admin/reports/:id — select from the pending list by id.
  readonly report = computed(() => this.reports().find((r) => r.id === this.reportId) ?? EMPTY_REPORT);

  ngOnInit(): void {
    this.admin.reports().subscribe({
      next: (reports) => {
        const list = reports ?? [];
        this.reports.set(list);
        // Already-reviewed reports drop out of the pending queue → return to it.
        if (this.reportId && !list.some((r) => r.id === this.reportId)) {
          this.router.navigate(['/admin/reports']);
        }
      },
      error: () => this.reports.set([]),
    });
  }

  ban(): void {
    const r = this.report();
    if (!r.id) return;
    this.admin.ban(r.reportedId).subscribe({
      next: () => {
        this.admin.review(r.id).subscribe({ error: () => {} });
        this.resolution.set('ban');
        this.toast.push('message', 'User banned', `${r.reportedName} has been removed.`);
      },
      error: () => {},
    });
  }

  dismiss(): void {
    const r = this.report();
    if (!r.id) return;
    this.admin.review(r.id).subscribe({
      next: () => {
        this.resolution.set('dismiss');
        this.toast.push('message', 'Report dismissed', 'No action taken.');
      },
      error: () => {},
    });
  }

  back(): void {
    this.router.navigate(['/admin/reports']);
  }
}
